include   // 需要包含这个头文件 <p>// 预分配的内存缓冲区 alignas(MyClass) uint8_t buffer[sizeof(MyClass)];</p> <p>// 在缓冲区中构造对象 MyClass* obj = new (buffer) MyClass();</p> <p>// 使用对象 obj-&gt;some_method();</p> <p>// 必须显式调用析构函数 obj-&gt;~MyClass();</p> <p>// 不要使用delete，因为内存不是用new分配的 ```text</p> <p>在嵌入式系统中，placement new在固定内存池中构造对象时很有用：</p> <p>```cpp class FixedMemoryPool { private:     static constexpr size_t POOL_SIZE = 1024;     alignas(max_align_t) uint8_t memory_pool[POOL_SIZE];     size_t used;</p> <p>public:     FixedMemoryPool() : used(0) {}</p> <pre><code>void* allocate(size_t size, size_t alignment = alignof(max_align_t)) {
    // 对齐地址
    size_t padding = (alignment - (used % alignment)) % alignment;
    size_t new_used = used + padding + size;

    if (new_used &gt; POOL_SIZE) {
        return nullptr;  // 内存池已满
    }

    void* ptr = &amp;memory_pool[used + padding];
    used = new_used;
    return ptr;
}

void reset() {
    used = 0;
}
</code></pre> <p>};</p> <p>// 使用 FixedMemoryPool pool;</p> <p>// 在池中构造对象 void* mem = pool.allocate(sizeof(MyClass), alignof(MyClass)); if (mem) {     MyClass* obj = new (mem) MyClass();     // 使用obj     obj-&gt;~MyClass();  // 显式调用析构函数 } ```text</p>

include  <p>class GPIO { private:     // 硬件寄存器定义（藏在private里，外人别乱碰）     static constexpr uint32_t GPIO_BASE = 0x40020000;     static volatile uint32_t&amp; GPIO_ODR() {         return *reinterpret_cast(GPIO_BASE + 0x14);     }     static volatile uint32_t&amp; GPIO_BSRR() {         return *reinterpret_cast(GPIO_BASE + 0x18);     } <pre><code>uint8_t pin_;
bool state_;
uint8_t pwm_duty_;
</code></pre> <p>public:     // 构造函数（一出生就知道自己是谁）     explicit GPIO(uint8_t pin) : pin_(pin), state_(false), pwm_duty_(0) {}</p> <pre><code>// 禁用拷贝（硬件资源不能克隆，你能复制一个LED吗？）
GPIO(const GPIO&amp;) = delete;
GPIO&amp; operator=(const GPIO&amp;) = delete;

// 写入状态
void write(bool value) {
    if (value) {
        GPIO_BSRR() = (1U &lt;&lt; pin_);
    } else {
        GPIO_BSRR() = (1U &lt;&lt; (pin_ + 16));
    }
    state_ = value;
}

// 切换状态
void toggle() {
    write(!state_);
}

// 设置PWM占空比
void setPWM(uint8_t duty) {
    pwm_duty_ = (duty &gt; 100) ? 100 : duty;
}

// 读取状态
bool read() const {
    return state_;
}

// 运算符重载：让代码看起来像在和LED聊天
GPIO&amp; operator=(bool value) {
    write(value);
    return *this;
}

operator bool() const {
    return read();
}
</code></pre> <p>};</p> <p>// 使用示例（看起来更像是在"对话"而不是"操作"） void example_cpp() {     GPIO led(5);  // 创建一个GPIO对象，它自己知道初始化</p> <pre><code>led.write(true);
led.toggle();
led.setPWM(75);

// 或者使用更直观的语法（就像在说"led你给我开！"）
led = true;
if (led) {  // 可以直接当bool用！
    led = false;
}
</code></pre> <p>} ```text</p> <p>C++中的一个经典的使用，就是采用OOP面对对象的编程思路进行编程。</p> <p>当然一些朋友会抬杠——谁告诉你，C++是一个OOP语言的？它也是泛型编程语言。也对，我没意见，笔者自己的GPIO库就是用模板写的，不过这里，我们先考虑OOP。</p>

define BUFFER_SIZE 64  // 64字节，不大不小刚刚好 <p>typedef struct {     uint8_t buffer[BUFFER_SIZE];     volatile uint16_t head;   // 写指针（放盘子的位置）     volatile uint16_t tail;   // 读指针（拿盘子的位置）     volatile uint16_t count;  // 当前有多少盘子 } RingBuffer;</p> <p>// 初始化（把转台清空） void rb_init(RingBuffer* rb) {     rb-&gt;head = 0;     rb-&gt;tail = 0;     rb-&gt;count = 0; }</p> <p>// 写入一个字节（放一个盘子上台） bool rb_put(RingBuffer* rb, uint8_t data) {     if (rb-&gt;count &gt;= BUFFER_SIZE) {         return false; // 转台满了，请稍后再试     }</p> <pre><code>rb-&gt;buffer[rb-&gt;head] = data;
rb-&gt;head = (rb-&gt;head + 1) % BUFFER_SIZE;  // 绕圈圈
rb-&gt;count++;
return true;
</code></pre> <p>}</p> <p>// 读取一个字节（拿一个盘子） bool rb_get(RingBuffer* rb, uint8_t* data) {     if (rb-&gt;count == 0) {         return false; // 转台空了，没东西可拿     }</p> <pre><code>*data = rb-&gt;buffer[rb-&gt;tail];
rb-&gt;tail = (rb-&gt;tail + 1) % BUFFER_SIZE;  // 绕圈圈
rb-&gt;count--;
return true;
</code></pre> <p>}</p> <p>// 查询还有多少数据（还有多少盘子） uint16_t rb_available(RingBuffer* rb) {     return rb-&gt;count; }</p> <p>// 查询还有多少空间（还能放多少盘子） uint16_t rb_free_space(RingBuffer* rb) {     return BUFFER_SIZE - rb-&gt;count; }</p> <p>// 清空缓冲区（把转台上的盘子全部拿走） void rb_clear(RingBuffer* rb) {     rb-&gt;head = 0;     rb-&gt;tail = 0;     rb-&gt;count = 0; }</p> <p>// 使用示例 void example_c_rb(void) {     RingBuffer uart_rx;     rb_init(&amp;uart_rx);</p> <pre><code>// 写入数据（发送"Hello"）
const char* msg = "Hello";
for (int i = 0; msg[i]; i++) {
    rb_put(&amp;uart_rx, msg[i]);
}

// 读取数据（接收并处理）
uint8_t byte;
while (rb_get(&amp;uart_rx, &amp;byte)) {
    // 处理每个字节
}
</code></pre> <p>} ```text</p>

include  <p>// 模板参数：想要多大的转台，你说了算！ template class RingBuffer { private:     std::array buffer_;  // 用std::array而不是C数组     volatile uint16_t head_{0};     volatile uint16_t tail_{0};     volatile uint16_t count_{0}; <p>public:     // 构造函数（转台出厂就是干净的）     RingBuffer() = default;</p> <pre><code>// 写入一个字节
bool put(uint8_t data) {
    if (count_ &gt;= Size) {
        return false;
    }

    buffer_[head_] = data;
    head_ = (head_ + 1) % Size;
    count_++;
    return true;
}

// 读取一个字节（注意：这里用引用返回，避免指针）
bool get(uint8_t&amp; data) {
    if (count_ == 0) {
        return false;
    }

    data = buffer_[tail_];
    tail_ = (tail_ + 1) % Size;
    count_--;
    return true;
}

// 批量写入（一次放多个盘子）
size_t write(const uint8_t* data, size_t len) {
    size_t written = 0;
    for (size_t i = 0; i &lt; len &amp;&amp; put(data[i]); i++) {
        written++;
    }
    return written;
}

// 批量读取（一次拿多个盘子）
size_t read(uint8_t* data, size_t len) {
    size_t read_count = 0;
    for (size_t i = 0; i &lt; len &amp;&amp; get(data[i]); i++) {
        read_count++;
    }
    return read_count;
}

// 查询方法（[[nodiscard]]告诉编译器：别忽略返回值！）
[[nodiscard]] uint16_t available() const { return count_; }
[[nodiscard]] uint16_t freeSpace() const { return Size - count_; }
[[nodiscard]] bool isEmpty() const { return count_ == 0; }
[[nodiscard]] bool isFull() const { return count_ &gt;= Size; }

// 清空
void clear() {
    head_ = 0;
    tail_ = 0;
    count_ = 0;
}

// 获取容量（编译期常量，不占运行时间）
static constexpr size_t capacity() { return Size; }
</code></pre> <p>};</p> <p>// 使用示例（注意模板参数可以在编译期指定大小） void example_cpp_rb() {     RingBuffer&lt;64&gt; uart_rx;  // 64字节的缓冲区</p> <pre><code>// 写入数据
const char* msg = "Hello";
uart_rx.write(reinterpret_cast&lt;const uint8_t*&gt;(msg), strlen(msg));

// 读取数据
uint8_t byte;
while (uart_rx.get(byte)) {
    // 处理每个字节
}

// 或者批量读取
uint8_t buffer[32];
size_t n = uart_rx.read(buffer, sizeof(buffer));
</code></pre> <p>} ```text</p>

include  <p>// 按键状态（状态机的"房间"） typedef enum {     BTN_STATE_IDLE,        // 闲置状态（没人按）     BTN_STATE_PRESSED,     // 按下状态（刚按下）     BTN_STATE_RELEASED,    // 释放状态（刚松开）     BTN_STATE_LONG_PRESS   // 长按状态（按了很久） } ButtonState;</p> <p>// 按键事件（状态机的"输出"） typedef enum {     BTN_EVENT_NONE,     BTN_EVENT_PRESS,       // 检测到短按     BTN_EVENT_RELEASE,     // 检测到释放     BTN_EVENT_LONG_PRESS   // 检测到长按 } ButtonEvent;</p> <p>// 按键状态机结构体 typedef struct {     ButtonState state;     uint32_t timestamp;         // 时间戳（记录何时进入当前状态）     uint8_t pin;                // GPIO引脚     bool last_reading;          // 上次读数     uint16_t debounce_time;     // 消抖时间（ms）     uint16_t long_press_time;   // 长按时间（ms） } ButtonFSM;</p> <p>// 初始化 void btn_init(ButtonFSM* btn, uint8_t pin) {     btn-&gt;state = BTN_STATE_IDLE;     btn-&gt;timestamp = 0;     btn-&gt;pin = pin;     btn-&gt;last_reading = false;     btn-&gt;debounce_time = 50;     // 50ms消抖     btn-&gt;long_press_time = 1000; // 1s长按 }</p> <p>// 硬件接口（假设这些函数已经实现） extern bool hw_read_pin(uint8_t pin); extern uint32_t hw_get_tick(void);</p> <p>// 状态机更新（在主循环中不断调用） ButtonEvent btn_update(ButtonFSM* btn) {     bool reading = hw_read_pin(btn-&gt;pin);     uint32_t now = hw_get_tick();     ButtonEvent event = BTN_EVENT_NONE;</p> <pre><code>// 状态机核心：根据当前状态和输入决定下一步
switch (btn-&gt;state) {
    case BTN_STATE_IDLE:
        // 闲置状态：检测按下
        if (reading &amp;&amp; !btn-&gt;last_reading) {
            btn-&gt;timestamp = now;
            btn-&gt;state = BTN_STATE_PRESSED;
        }
        break;

    case BTN_STATE_PRESSED:
        // 按下状态：等待释放或长按
        if (!reading) {
            // 松开了
            if ((now - btn-&gt;timestamp) &gt;= btn-&gt;debounce_time) {
                event = BTN_EVENT_PRESS;  // 确认是有效按下
                btn-&gt;state = BTN_STATE_RELEASED;
                btn-&gt;timestamp = now;
            } else {
                btn-&gt;state = BTN_STATE_IDLE;  // 抖动，忽略
            }
        } else if ((now - btn-&gt;timestamp) &gt;= btn-&gt;long_press_time) {
            // 按太久了！
            event = BTN_EVENT_LONG_PRESS;
            btn-&gt;state = BTN_STATE_LONG_PRESS;
        }
        break;

    case BTN_STATE_RELEASED:
        // 释放状态：确认释放
        if ((now - btn-&gt;timestamp) &gt;= btn-&gt;debounce_time) {
            if (!reading) {
                event = BTN_EVENT_RELEASE;
                btn-&gt;state = BTN_STATE_IDLE;
            } else {
                btn-&gt;state = BTN_STATE_PRESSED;  // 又按下了？
                btn-&gt;timestamp = now;
            }
        }
        break;

    case BTN_STATE_LONG_PRESS:
        // 长按状态：等待释放
        if (!reading) {
            btn-&gt;state = BTN_STATE_IDLE;
        }
        break;
}

btn-&gt;last_reading = reading;
return event;
</code></pre> <p>}</p> <p>// 使用示例 void example_c_button(void) {     ButtonFSM power_button;     btn_init(&amp;power_button, 3);  // 使用GPIO 3</p> <pre><code>// 在主循环中调用
while (1) {
    ButtonEvent evt = btn_update(&amp;power_button);
    switch (evt) {
        case BTN_EVENT_PRESS:
            // 短按：切换开关
            break;
        case BTN_EVENT_LONG_PRESS:
            // 长按：进入设置菜单
            break;
        case BTN_EVENT_RELEASE:
            // 释放：什么都不做
            break;
        default:
            break;
    }
}
</code></pre> <p>} ```text</p>

include  <p>// 硬件接口（假设这些函数已经实现） extern bool hw_read_pin(uint8_t pin); extern uint32_t hw_get_tick(void);</p> <p>class Button { public:     // 事件类型（用enum class更安全）     enum class Event {         None,         Press,         Release,         LongPress     };</p> <pre><code>// 回调函数类型（可以是lambda、函数指针等）
using EventCallback = std::function&lt;void(Event)&gt;;
</code></pre> <p>private:     // 内部状态（外人看不到）     enum class State {         Idle,         Pressed,         Released,         LongPress     };</p> <pre><code>State state_{State::Idle};
uint32_t timestamp_{0};
uint8_t pin_;
bool last_reading_{false};
uint16_t debounce_time_{50};
uint16_t long_press_time_{1000};
EventCallback callback_;  // 事件回调

// 硬件接口（封装在内部）
bool readPin() const {
    return hw_read_pin(pin_);
}

uint32_t getTick() const {
    return hw_get_tick();
}

// 通知事件（如果有回调的话）
void notifyEvent(Event event) {
    if (callback_ &amp;&amp; event != Event::None) {
        callback_(event);
    }
}
</code></pre> <p>public:     // 构造函数（可以自定义消抖和长按时间）     explicit Button(uint8_t pin,                    uint16_t debounce_ms = 50,                    uint16_t long_press_ms = 1000)         : pin_(pin)         , debounce_time_(debounce_ms)         , long_press_time_(long_press_ms) {}</p> <pre><code>// 设置回调函数（支持lambda表达式）
void setCallback(EventCallback callback) {
    callback_ = callback;
}

// 状态机更新
Event update() {
    bool reading = readPin();
    uint32_t now = getTick();
    Event event = Event::None;

    switch (state_) {
        case State::Idle:
            if (reading &amp;&amp; !last_reading_) {
                timestamp_ = now;
                state_ = State::Pressed;
            }
            break;

        case State::Pressed:
            if (!reading) {
                if ((now - timestamp_) &gt;= debounce_time_) {
                    event = Event::Press;
                    state_ = State::Released;
                    timestamp_ = now;
                } else {
                    state_ = State::Idle;
                }
            } else if ((now - timestamp_) &gt;= long_press_time_) {
                event = Event::LongPress;
                state_ = State::LongPress;
            }
            break;

        case State::Released:
            if ((now - timestamp_) &gt;= debounce_time_) {
                if (!reading) {
                    event = Event::Release;
                    state_ = State::Idle;
                } else {
                    state_ = State::Pressed;
                    timestamp_ = now;
                }
            }
            break;

        case State::LongPress:
            if (!reading) {
                state_ = State::Idle;
            }
            break;
    }

    last_reading_ = reading;
    notifyEvent(event);  // 自动通知回调
    return event;
}

// 查询方法
[[nodiscard]] bool isPressed() const {
    return state_ == State::Pressed || state_ == State::LongPress;
}
</code></pre> <p>};</p> <p>// 使用示例（看看C++的回调有多爽） void example_cpp_button() {     Button power_button(3);</p> <pre><code>// 使用lambda表达式作为回调
power_button.setCallback([](Button::Event evt) {
    switch (evt) {
        case Button::Event::Press:
            // 短按：切换开关
            break;
        case Button::Event::LongPress:
            // 长按：进入设置菜单
            break;
        case Button::Event::Release:
            // 释放：什么都不做
            break;
        default:
            break;
    }
});

// 在主循环中调用
while (true) {
    power_button.update();  // 自动调用回调
}
</code></pre> <p>}</p> <p>// 如果不想用std::function（它有点重），可以用函数指针版本 class ButtonLite { public:     enum class Event { None, Press, Release, LongPress };     using EventCallback = void (*)(Event);  // 函数指针，更轻量</p> <pre><code>// ... 其他实现类似，但用函数指针代替std::function
</code></pre> <p>}; ```text</p>

include  <p>template class ThreadSafeQueue { public:     void push(const T&amp; value) {         std::lock_guard lock(mtx);         queue.push(value);         cv.notify_one();  // 通知一个等待的线程     } <pre><code>T pop() {
    std::unique_lock&lt;std::mutex&gt; lock(mtx);  // 必须用unique_lock

    // wait会在条件不满足时解锁，被唤醒时重新加锁
    cv.wait(lock, [this] { return !queue.empty(); });

    T value = queue.front();
    queue.pop();
    return value;

    // lock离开作用域自动解锁
}
</code></pre> <p>private:     std::queue queue;     std::mutex mtx;     std::condition_variable cv; }; ```text <p>这是<code>unique_lock</code>不可替代的场景。如果你要用条件变量，就必须用<code>unique_lock</code>。</p>

include  <p>class ThreadSafeMap { public:     void insert(const std::string&amp; key, int value) {         std::unique_lock lock(mtx);  // 写锁：独占         map[key] = value;     } <pre><code>int lookup(const std::string&amp; key) const {
    std::shared_lock&lt;std::shared_mutex&gt; lock(mtx);  // 读锁：共享
    auto it = map.find(key);
    return (it != map.end()) ? it-&gt;second : 0;
}
</code></pre> <p>private:     mutable std::shared_mutex mtx;     std::map map; }; ```text <p>特性：</p> <ul> <li><code>unique_lock</code>：写锁，独占访问</li> <li><code>shared_lock</code>：读锁，多个线程可以同时持有</li> <li>写操作会阻塞所有读写，读操作只阻塞写操作</li> </ul> <p>性能：在读者很多、写者很少的场景，<code>shared_mutex</code>比普通mutex性能好很多。但要注意它的开销比普通mutex大，不要盲目使用。</p> <p>嵌入式注意：某些嵌入式平台的<code>shared_mutex</code>可能不支持或者实现很重，使用前检查文档和性能。</p>

include  <p>// 状态与事件 enum class DebState : uint8_t { Idle=0, Bounce=1, Pressed=2, Count=3 }; enum class DebEvent : uint8_t { EdgeDown=0, EdgeUp=1, Timeout=2, Count=3 };</p> <p>// 动作类型 using ActionFn = void()(void ctx);</p> <p>// 转移表条目 struct Transition {     DebState from;     DebEvent event;     DebState to;     ActionFn action; // 可为 nullptr };</p> <p>// 示例动作 inline void start_timer(void* ctx) { /* start timer with ctx / } inline void report_press(void ctx) { /* notify / } inline void report_release(void ctx) { /* notify */ }</p> <p>// constexpr 转移表 constexpr Transition debounce_table[] = {     {DebState::Idle,   DebEvent::EdgeDown, DebState::Bounce, start_timer},     {DebState::Bounce, DebEvent::Timeout,  DebState::Pressed, report_press},     {DebState::Pressed,DebEvent::EdgeUp,   DebState::Idle,    report_release},     {DebState::Bounce, DebEvent::EdgeUp,   DebState::Idle,    nullptr}, };</p> <p>constexpr size_t TRANS_COUNT = sizeof(debounce_table) / sizeof(debounce_table[0]);</p> <p>// 小型状态机实现（表驱动） struct Debouncer {     DebState state{DebState::Idle};     void* ctx{nullptr};</p> <pre><code>void handle(DebEvent ev) {
    for (size_t i = 0; i &lt; TRANS_COUNT; ++i) {
        auto &amp;t = debounce_table[i];
        if (t.from == state &amp;&amp; t.event == ev) {
            state = t.to;
            if (t.action) t.action(ctx);
            return;
        }
    }
    // 未找到转移：忽略或断言（取决于策略）
}
</code></pre> <p>}; ```text</p> <p>上面这个是一个玩具实现，如果，咱们需要在编译期检查每个 (state,event) 是否都有 handler，可以把表转成 <code>constexpr</code> 二维数组（<code>std::array&lt;std::array&lt;TransitionOrEmpty, EventCount&gt;, StateCount&gt;</code>）并 <code>static_assert</code> 无缺失。</p>

endif <p>// ========== 同步策略接口 ========== // 这些策略为空壳或实现平台相关的保护操作</p> <p>struct NoLockPolicy {     static void lock() {}     static void unlock() {} };</p> <p>// 关中断保护（伪代码，需由平台实现） struct InterruptLockPolicy {     static inline unsigned primask_save() { unsigned p = 0; /* read PRIMASK / return p; }     static inline void primask_restore(unsigned p) { / write PRIMASK */ }     unsigned state;     InterruptLockPolicy() : state(primask_save()) {}     ~InterruptLockPolicy() { primask_restore(state); } };</p> <p>// 基于 mutex 的保护（RTOS） struct MutexLockPolicy {     static void lock();   // 在平台文件中实现     static void unlock(); };</p> <p>// ========== 对象池实现 ==========</p> <p>template class ObjectPool { public:     static_assert(N &gt; 0, "Pool size must be &gt; 0");     static_assert(std::is_default_constructible::value || std::is_trivially_default_constructible::value,                   "T must be default constructible or trivially default constructible for placement new usage"); <pre><code>ObjectPool() {
    for (size_t i = 0; i &lt; N; ++i) {
        next_idx_[i] = (i + 1 &lt; N) ? i + 1 : kInvalidIndex;
    }
    free_head_ = 0;
}

// 非阻塞借出，耗尽返回 nullptr
T* try_acquire() {
    Sync::lock();
    if (free_head_ == kInvalidIndex) {
        Sync::unlock();
        return nullptr;
    }
    size_t idx = free_head_;
    free_head_ = next_idx_[idx];
    used_count_++;
