include  <p>// Intrusive list node base — 继承它即可成为链表节点 template struct IntrusiveListNode {     T* prev = nullptr;     T* next = nullptr; }; <p>// Intrusive doubly linked list template class IntrusiveList { public:     IntrusiveList() : head(nullptr), tail(nullptr) {} <pre><code>bool empty() const { return head == nullptr; }

void push_front(T* node) {
    assert(node &amp;&amp; node-&gt;prev == nullptr &amp;&amp; node-&gt;next == nullptr &amp;&amp; "节点必须处于未链接状态");
    node-&gt;next = head;
    if (head) head-&gt;prev = node;
    head = node;
    if (!tail) tail = node;
}

void push_back(T* node) {
    assert(node &amp;&amp; node-&gt;prev == nullptr &amp;&amp; node-&gt;next == nullptr &amp;&amp; "节点必须处于未链接状态");
    node-&gt;prev = tail;
    if (tail) tail-&gt;next = node;
    tail = node;
    if (!head) head = node;
}

T* pop_front() {
    if (!head) return nullptr;
    T* n = head;
    head = head-&gt;next;
    if (head) head-&gt;prev = nullptr;
    else tail = nullptr;
    n-&gt;next = n-&gt;prev = nullptr;
    return n;
}

