include  <p>// 零开销回调类型 template using Callback = ZeroCallback; <p>// 事件类型 enum class EventType : uint8_t {     GPIO_CHANGED,     ADC_COMPLETE,     TIMER_EXPIRED,     UART_RX,     MAX_EVENTS };</p> <p>// 事件系统 class EventSystem { public:     using Handler = Callback; <pre><code>struct Slot {
    Handler callback;
    uint32_t user_data;

    Slot() = default;
    Slot(Handler cb, uint32_t data = 0)
        : callback(std::move(cb)), user_data(data) {}
};

// 注册事件处理器
bool register_handler(EventType evt, Handler cb, uint32_t data = 0) {
    auto idx = static_cast&lt;size_t&gt;(evt);
    if (handlers[idx].callback.empty()) {
        handlers[idx] = {std::move(cb), data};
        return true;
    }
    return false;  // 槽已占用
}

// 触发事件（从中断调用）
void __attribute__((always_inline)) trigger(EventType evt, uint32_t param = 0) {
    auto idx = static_cast&lt;size_t&gt;(evt);
    if (!handlers[idx].callback.empty()) {
        handlers[idx].callback(param | handlers[idx].user_data);
    }
}
</code></pre> <p>private:     std::array(EventType::MAX_EVENTS)&gt; handlers; }; ```text  查看完整可编译示例  ```cpp // Zero Overhead Event System // A complete event handling system for embedded systems  #include  #include  #include  #include   // ZeroCallback implementation template class ZeroCallback;  template class ZeroCallback {     struct VTable {         void (*move)(void* dest, void* src);         void (*destroy)(void* obj);         R (*invoke)(void* obj, Args...);     };      alignas(std::max_align_t) std::byte storage[Size];     const VTable* vtable = nullptr;      template     struct VTableFor {         static void do_move(void* dest, void* src) {             new(dest) T(std::move(*reinterpret_cast(src)));         }         static void do_destroy(void* obj) {             reinterpret_cast(obj)-&gt;~T();         }         static R do_invoke(void* obj, Args... args) {             return (*reinterpret_cast(obj))(args...);         }         static constexpr VTable value = {do_move, do_destroy, do_invoke};     };  public:     ZeroCallback() = default;      template     ZeroCallback(T&amp;&amp; callable) {         using TDecay = std::decay_t;         static_assert(sizeof(TDecay) &lt;= Size, "Callable too large");         new(storage) TDecay(std::forward(callable));         vtable = &amp;VTableFor::value;     }      ZeroCallback(ZeroCallback&amp;&amp; other) noexcept : vtable(other.vtable) {         if (vtable) {             vtable-&gt;move(storage, other.storage);             other.vtable = nullptr;         }     }      ~ZeroCallback() {         if (vtable) {             vtable-&gt;destroy(storage);         }     }      ZeroCallback(const ZeroCallback&amp;) = delete;     ZeroCallback&amp; operator=(const ZeroCallback&amp;) = delete;      R operator()(Args... args) const {         return vtable-&gt;invoke(const_cast(storage), args...);     }      bool empty() const { return vtable == nullptr; } };  // Event types enum class EventType : uint8_t {     GPIO_CHANGED,     ADC_COMPLETE,     TIMER_EXPIRED,     UART_RX,     MAX_EVENTS };  // Event system class EventSystem { public:     using Handler = ZeroCallback;      struct Slot {         Handler callback;         uint32_t user_data;          Slot() = default;         Slot(Handler cb, uint32_t data = 0)             : callback(std::move(cb)), user_data(data) {}     };      bool register_handler(EventType evt, Handler cb, uint32_t data = 0) {         auto idx = static_cast(evt);         if (!handlers[idx].callback.empty()) {             return false;  // Slot already occupied         }         handlers[idx] = {std::move(cb), data};         return true;     }      void trigger(EventType evt, uint32_t param = 0) {         auto idx = static_cast(evt);         if (!handlers[idx].callback.empty()) {             handlers[idx].callback(param | handlers[idx].user_data);         }     }  private:     std::array(EventType::MAX_EVENTS)&gt; handlers{}; };  // Button driver class ButtonDriver {     int pin;     int press_count = 0;  public:     ButtonDriver(int p) : pin(p) {}      void init(EventSystem&amp; events) {         events.register_handler(EventType::GPIO_CHANGED,             [this](uint32_t pins) {                 if (pins &amp; (1 &lt;&lt; pin)) {                     press_count++;                     on_press();                 }             });     }      void on_press() {         std::cout &lt;&lt; "Button on pin " &lt;&lt; pin &lt;&lt; " pressed (count: "                   &lt;&lt; press_count &lt;&lt; ")" &lt;&lt; std::endl;     } };  // LED controller class LEDController {     int pin;     bool state = false;  public:     LEDController(int p) : pin(p) {}      void init(EventSystem&amp; events) {         events.register_handler(EventType::TIMER_EXPIRED,             [this](uint32_t) {                 state = !state;                 std::cout &lt;&lt; "LED pin " &lt;&lt; pin &lt;&lt; " -&gt; "                           &lt;&lt; (state ? "ON" : "OFF") &lt;&lt; std::endl;             });     } };  // ADC handler void setup_adc(EventSystem&amp; events) {     events.register_handler(EventType::ADC_COMPLETE,         [](uint32_t channel) {             std::cout &lt;&lt; "ADC conversion complete, channel: "                       &lt;&lt; channel &lt;&lt; ", value: " &lt;&lt; (2048 + channel * 100) &lt;&lt; std::endl;         }); }  int main() {     std::cout &lt;&lt; "=== Zero Overhead Event System Demo ===" &lt;&lt; std::endl;      EventSystem g_events;      // Initialize devices     ButtonDriver btn(5);     btn.init(g_events);      LEDController led(10);     led.init(g_events);      setup_adc(g_events);      // Simulate interrupts     std::cout &lt;&lt; "\n--- Simulating Events ---" &lt;&lt; std::endl;      g_events.trigger(EventType::GPIO_CHANGED, 0x20);  // Button press     g_events.trigger(EventType::TIMER_EXPIRED, 0);    // LED toggle     g_events.trigger(EventType::ADC_COMPLETE, 0);     // ADC done     g_events.trigger(EventType::GPIO_CHANGED, 0x20);  // Another button press     g_events.trigger(EventType::TIMER_EXPIRED, 0);    // LED toggle      std::cout &lt;&lt; "\n=== Performance Characteristics ===" &lt;&lt; std::endl;     std::cout &lt;&lt; "- No heap allocation (stack storage only)" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Single indirection through function pointer" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Compiler can inline in many cases" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Suitable for interrupt handlers" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Fixed overhead per callback (~24 bytes)" &lt;&lt; std::endl;      return 0; }  ```text

