ResultType(); }  // Test functions struct Calculator {     int add(int a, int b) const {         volatile int x = a + b;  // Prevent optimization         return x;     } };  int compute(int x, int y) {     volatile int sum = 0;     for (int i = 0; i &lt; 1000; ++i) {         sum += x * y;     }     return sum; }  // Demo void demo_timed_wrapper() {     std::cout &lt;&lt; "=== Timed Wrapper Demo ===" &lt;&lt; std::endl;      Calculator calc;      std::cout &lt;&lt; "Free function: ";     timed_invoke(compute, 5, 3);      std::cout &lt;&lt; "Member function: ";     timed_invoke(&amp;Calculator::add, calc, 10, 20);      std::cout &lt;&lt; "Lambda: ";     timed_invoke([]() { return compute(7, 11); }); }  void demo_logged_wrapper() {     std::cout &lt;&lt; "\n=== Logged Wrapper Demo ===" &lt;&lt; std::endl;      Calculator calc;      auto result = logged_invoke("add", &amp;Calculator::add, calc, 5, 3);     std::cout &lt;&lt; "Result: " &lt;&lt; result &lt;&lt; std::endl; }  // Perfect forwarding demo template auto forward_and_call(Func&amp;&amp; func, Args&amp;&amp;... args)     -&gt; decltype(std::invoke(std::forward(func), std::forward(args)...)) {     return std::invoke(std::forward(func), std::forward(args)...); }  void take_by_value(int x) {     std::cout &lt;&lt; "by value: " &lt;&lt; x &lt;&lt; std::endl; }  void take_by_lvalue_ref(int&amp; x) {     std::cout &lt;&lt; "by lvalue ref: " &lt;&lt; x &lt;&lt; std::endl;     x *= 2; }  void demo_perfect_forwarding() {     std::cout &lt;&lt; "\n=== Perfect Forwarding Demo ===" &lt;&lt; std::endl;      int value = 10;      forward_and_call(take_by_value, value);     forward_and_call(take_by_lvalue_ref, value);     std::cout &lt;&lt; "After lvalue ref: " &lt;&lt; value &lt;&lt; std::endl; }  // Type-safe wrapper with constraints template auto safe_call(Func&amp;&amp; func, Args&amp;&amp;... args)     -&gt; decltype(std::invoke(std::forward(func), std::forward(args)...)) {     using Result = decltype(std::invoke(std::forward(func), std::forward(args)...));      if constexpr (std::is_void_v) {         std::invoke(std::forward(func), std::forward(args)...);         std::cout &lt;&lt; "(void return)" &lt;&lt; std::endl;     } else {         auto result = std::invoke(std::forward(func), std::forward(args)...);         std::cout &lt;&lt; "result: " &lt;&lt; result &lt;&lt; std::endl;         return result;     } }  void demo_safe_call() {     std::cout &lt;&lt; "\n=== Safe Call Demo ===" &lt;&lt; std::endl;      Calculator calc;      std::cout &lt;&lt; "Void lambda: ";     safe_call([]() { std::cout &lt;&lt; "Hello" &lt;&lt; std::endl; });      std::cout &lt;&lt; "Returning lambda: ";     safe_call([]() { return 42; }); }  int main() {     demo_timed_wrapper();     demo_logged_wrapper();     demo_perfect_forwarding();     demo_safe_call();      return 0; }  ```text

include  <p>struct Multiplier {     double operator()(int x, int y) const {         return static_cast(x) * y;     } }; <p>void test_invoke_result() {     // 编译期推导返回类型     using Result1 = std::invoke_result_t;     static_assert(std::is_same_v); <pre><code>// 用于模板约束
