include  <p>class CommandParser { public:     // 注册命令——接受任何可调用对象     template     void register_command(const std::string&amp; name, Func&amp;&amp; handler) {         commands_[name] = CommandWrapper{std::forward(handler)};     } <pre><code>// 执行命令
