</code></pre> <p>} ```text</p> <p>这个例子里，<code>std::invoke</code>让我们能够统一处理全局函数、Lambda和成员函数。命令注册的代码非常干净，调用者不需要关心底层是什么类型。</p>  查看完整可编译示例  ```cpp // Command Parser using std::invoke // Demonstrates a CLI system that handles different callable types uniformly  #include  #include  #include  #include  #include   class CommandParser { public:     // Register any callable as a command handler     template     void register_command(const std::string&amp; name, Func&amp;&amp; handler) {         commands_[name] = CommandWrapper{std::forward(handler)};     }      // Execute command     bool execute(const std::string&amp; line) {         std::istringstream iss(line);         std::string cmd;         iss &gt;&gt; cmd;          auto it = commands_.find(cmd);         if (it == commands_.end()) {             std::cout &lt;&lt; "Unknown command: " &lt;&lt; cmd &lt;&lt; std::endl;             return false;         }          return it-&gt;second.invoke(iss);     }  private:     struct CommandWrapper {         std::function invoke;     };      std::unordered_map commands_; };  // Global function handler bool handle_set(std::istringstream&amp; iss) {     std::string key, value;     iss &gt;&gt; key &gt;&gt; value;     std::cout &lt;&lt; "Set " &lt;&lt; key &lt;&lt; " = " &lt;&lt; value &lt;&lt; std::endl;     return true; }  bool handle_list(std::istringstream&amp;) {     std::cout &lt;&lt; "Listing all entries..." &lt;&lt; std::endl;     return true; }  // Class with member function handlers class ConfigManager {     std::unordered_map config_;  public:     bool handle_get(std::istringstream&amp; iss) {         std::string key;         iss &gt;&gt; key;         auto it = config_.find(key);         if (it != config_.end()) {             std::cout &lt;&lt; key &lt;&lt; " = " &lt;&lt; it-&gt;second &lt;&lt; std::endl;         } else {             std::cout &lt;&lt; key &lt;&lt; " not found" &lt;&lt; std::endl;         }         return true;     }      bool handle_delete(std::istringstream&amp; iss) {         std::string key;         iss &gt;&gt; key;         if (config_.erase(key)) {             std::cout &lt;&lt; "Deleted " &lt;&lt; key &lt;&lt; std::endl;         } else {             std::cout &lt;&lt; key &lt;&lt; " not found" &lt;&lt; std::endl;         }         return true;     }      void add_config(const std::string&amp; key, int value) {         config_[key] = value;     } };  // Helper to create command wrapper from member function template auto make_command(T* obj, bool (T::*method)(std::istringstream&amp;)) {     return [obj, method](std::istringstream&amp; iss) {         return std::invoke(method, obj, iss);     }; }  int main() {     std::cout &lt;&lt; "=== Command Parser Demo ===" &lt;&lt; std::endl;      CommandParser parser;     ConfigManager config;      // Add some initial config     config.add_config("baudrate", 115200);     config.add_config("timeout", 1000);      // Register global functions     parser.register_command("set", handle_set);     parser.register_command("list", handle_list);      // Register member functions using std::invoke     parser.register_command("get", [&amp;config](std::istringstream&amp; iss) {         return std::invoke(&amp;ConfigManager::handle_get, config, iss);     });      parser.register_command("delete", [&amp;config](std::istringstream&amp; iss) {         return std::invoke(&amp;ConfigManager::handle_delete, config, iss);     });      // Register lambda     parser.register_command("help", [](std::istringstream&amp;) {         std::cout &lt;&lt; "Available commands: set, get, delete, list, help" &lt;&lt; std::endl;         return true;     });      // Execute commands     std::cout &lt;&lt; "\n--- Executing Commands ---" &lt;&lt; std::endl;      parser.execute("help");     parser.execute("get baudrate");     parser.execute("set address 0x1000");     parser.execute("get timeout");     parser.execute("list");     parser.execute("delete timeout");     parser.execute("unknown");      std::cout &lt;&lt; "\n=== Key Benefits ===" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Uniform interface for all callable types" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Easy to add global functions, member functions, or lambdas" &lt;&lt; std::endl;     std::cout &lt;&lt; "- std::invoke handles member function syntax automatically" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Type-safe at compile time" &lt;&lt; std::endl;      return 0; }  ```text

