sult parse_json(const std::string&amp; content) {     if (content.empty() || content[0] != '{') {         return ConfigError::parse_error("not a JSON object");     }     return JsonValue{content}; }  // Step 3: Validate and extract config Result validate_config(const JsonValue&amp; json) {     Config cfg;      // Simplified parsing     if (json.raw.find("baudrate") == std::string::npos) {         return ConfigError::validation_error("baudrate");     }     if (json.raw.find("timeout") == std::string::npos) {         return ConfigError::validation_error("timeout");     }      // Extract values (simplified)     cfg.baudrate = 115200;  // Would parse from JSON     cfg.timeout = 1000;      return cfg; }  // Step 4: Apply config Result apply_config(const Config&amp; cfg) {     std::cout &lt;&lt; "Applying configuration..." &lt;&lt; std::endl;     cfg.print();     return {};  // Success }  // TRY macro for clean error propagation #define TRY(...) ({ \     auto _result = (__VA_ARGS__); \     if (!_result) return std::unexpected(_result.error()); \     _result.value(); \ })  // Load pipeline using manual propagation Result load_config_manual(const std::string&amp; path) {     auto content_result = read_file(path);     if (!content_result) return content_result.error();      auto json_result = parse_json(content_result.value());     if (!json_result) return json_result.error();      auto config_result = validate_config(json_result.value());     if (!config_result) return config_result.error();      return apply_config(config_result.value()); }  // Load pipeline using TRY macro Result load_config_clean(const std::string&amp; path) {     auto content = TRY(read_file(path));     auto json = TRY(parse_json(content));     auto config = TRY(validate_config(json));     return apply_config(config); }  // Nested and_then approach Result load_config_functional(const std::string&amp; path) {     return read_file(path)         .and_then([](const std::string&amp; content) {             re