include  <p>// 重试包装器 template auto retry_with_backoff(F&amp;&amp; func,                         unsigned max_attempts,                         std::chrono::duration initial_delay)     -&gt; decltype(func()) {     using ResultType = decltype(func()); <pre><code>auto delay = initial_delay;
for (unsigned attempt = 0; attempt &lt; max_attempts; ++attempt) {
    auto result = func();

    if (result) {
        return result;  // 成功，直接返回
    }

    // 最后一次尝试失败，不再等待
    if (attempt == max_attempts - 1) {
        return result;
    }

    // 等待后重试
    std::this_thread::sleep_for(delay);
    delay *= 2;  // 指数退避
}

return ResultType();  // 不应该到这里
