ings -&gt; celsius -&gt; fahrenheit -&gt; display     auto display_data = readings         | std::views::filter([](const SensorReading&amp; r) { return r.valid; })         | std::views::transform([](const SensorReading&amp; r) {             float c = r.to_celsius();             return std::make_pair(r.sensor_id, c * 9.0f / 5.0f + 32.0f);         })         | std::views::filter([](const auto&amp; p) {             return p.second &gt;= -58 &amp;&amp; p.second &lt;= 302;  // Valid F range         });      std::cout &lt;&lt; "Sensor readings (F):" &lt;&lt; std::endl;     for (const auto&amp; [id, temp_f] : display_data) {         std::cout &lt;&lt; "  Sensor " &lt;&lt; static_cast(id) &lt;&lt; ": "                   &lt;&lt; std::fixed &lt;&lt; std::setprecision(1) &lt;&lt; temp_f &lt;&lt; " F" &lt;&lt; std::endl;     } }  void demo_voltage_display() {     std::cout &lt;&lt; "\n=== Voltage Display ===" &lt;&lt; std::endl;      auto readings = get_readings();      // Show voltage for valid readings     auto voltages = readings         | std::views::filter([](const SensorReading&amp; r) {             return r.valid &amp;&amp; r.raw_value &gt;= 100 &amp;&amp; r.raw_value &lt;= 4000;         })         | std::views::transform([](const SensorReading&amp; r) {             return std::make_tuple(r.sensor_id, r.to_voltage());         });      std::cout &lt;&lt; "Sensor voltages:" &lt;&lt; std::endl;     for (const auto&amp; [id, voltage] : voltages) {         std::cout &lt;&lt; "  Sensor " &lt;&lt; static_cast(id) &lt;&lt; ": "                   &lt;&lt; std::fixed &lt;&lt; std::setprecision(3) &lt;&lt; voltage &lt;&lt; " V" &lt;&lt; std::endl;     } }  void demo_statistics() {     std::cout &lt;&lt; "\n=== Statistics Pipeline ===" &lt;&lt; std::endl;      auto readings = get_readings();      // Get valid celsius readings for statistics     auto temps = readings         | std::views::filter([](const SensorReading&amp; r) { return r.valid; })         | std::views::transform([](const SensorReading&amp; r) { return r.to_celsius(); });      float sum = 0.0f;     size_t count = 0;     float min_val = 1000.0f;     float max_val = -1000.0f;      for (float t : temps) {         sum += t;         count++;         min_val = std::min(min_val, t);         max_val = std::max(max_val, t);     }      if (count &gt; 0) {         float avg = sum / count;         std::cout &lt;&lt; "Temperature statistics:" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Count: " &lt;&lt; count &lt;&lt; std::endl;         std::cout &lt;&lt; "  Min: " &lt;&lt; min_val &lt;&lt; " C" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Max: " &lt;&lt; max_val &lt;&lt; " C" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Avg: " &lt;&lt; avg &lt;&lt; " C" &lt;&lt; std::endl;     } }  void demo_alarm_check() {     std::cout &lt;&lt; "\n=== Alarm Check ===" &lt;&lt; std::endl;      auto readings = get_readings();      // Check for alarm conditions     auto alarms = readings         | std::views::filter([](const SensorReading&amp; r) { return r.valid; })         | std::views::transform([](const SensorReading&amp; r) {             return std::make_pair(r.sensor_id, r.to_celsius());         })         | std::views::filter([](const auto&amp; p) {             return p.second &gt; 80;  // High temp alarm         });      std::cout &lt;&lt; "High temperature alarms (&gt; 80 C):" &lt;&lt; std::endl;     for (const auto&amp; [id, temp] : alarms) {         std::cout &lt;&lt; "  ALARM: Sensor " &lt;&lt; static_cast(id)                   &lt;&lt; " at " &lt;&lt; temp &lt;&lt; " C" &lt;&lt; std::endl;     } }  void demo_processing_chain() {     std::cout &lt;&lt; "\n=== Complete Processing Chain ===" &lt;&lt; std::endl;      auto readings = get_readings();      // Full processing chain:     // 1. Filter valid readings     // 2. Filter reasonable ADC range     // 3. Convert to celsius     // 4. Filter reasonable temperature range     // 5. Convert to fahrenheit     // 6. Round to integer     auto processed = readings         | std::views::filter([](const SensorReading&amp; r) { return r.valid; })         | std::views::filter([](const SensorReading&amp; r) {             return r.raw_value &gt;= 500 &amp;&amp; r.raw_value &lt;= 3500;         })         | std::views::transform([](const SensorReading&amp; r) {             return r.to_celsius();         })         | std::views::filter([](float c) {             return c &gt;= 0 &amp;&amp; c &lt;= 100;         })         | std::views::transform([](float c) {             return static_cast(c * 9.0f / 5.0f + 32.0f);         });      std::cout &lt;&lt; "Processed values (int F): ";     for (int f : processed) {         std::cout &lt;&lt; f &lt;&lt; " F ";     }     std::cout &lt;&lt; std::endl; }  int main() {     demo_basic_pipeline();     demo_fahrenheit_pipeline();     demo_voltage_display();     demo_statistics();     demo_alarm_check();     demo_processing_chain();      std::cout &lt;&lt; "\n=== Key Points ===" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Views compose naturally into pipelines" &lt;&lt; std::endl;     std::cout &lt;&lt; "- No temporary allocations" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Single pass through data" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Perfect for embedded sensor processing" &lt;&lt; std::endl;      return 0; }  ```text

