, 2048, 2100, 100, 4100, 2000, 2050}) {         adc.add_sample(v);     }      auto results = adc.process();      std::cout &lt;&lt; "Processed voltages: " &lt;&lt; std::endl;     for (size_t i = 0; i &lt; results.size(); ++i) {         std::cout &lt;&lt; "  [" &lt;&lt; i &lt;&lt; "] " &lt;&lt; std::fixed &lt;&lt; std::setprecision(4)                   &lt;&lt; results[i] &lt;&lt; " V" &lt;&lt; std::endl;     } }  void demo_moving_average() {     std::cout &lt;&lt; "\n=== Moving Average ===" &lt;&lt; std::endl;      ADCProcessor adc;      // Add samples     for (uint16_t v : {2048, 2100, 2050, 2075, 2060}) {         adc.add_sample(v);     }      if (auto avg = adc.get_filtered_value()) {         std::cout &lt;&lt; "Average: " &lt;&lt; std::fixed &lt;&lt; std::setprecision(4)                   &lt;&lt; *avg &lt;&lt; " V" &lt;&lt; std::endl;     } }  void demo_stage_by_stage() {     std::cout &lt;&lt; "\n=== Stage-by-Stage Breakdown ===" &lt;&lt; std::endl;      std::vector samples = {50, 4500, 2048, 2100, 100};      std::cout &lt;&lt; "Original: ";     for (auto s : samples) {         std::cout &lt;&lt; s &lt;&lt; " ";     }     std::cout &lt;&lt; std::endl;      // Stage 1: Filter     auto stage1 = samples | std::views::filter([](uint16_t v) {         return v &gt;= 100 &amp;&amp; v &lt;= 4000;     });     std::cout &lt;&lt; "After filter: ";     for (auto v : stage1) {         std::cout &lt;&lt; v &lt;&lt; " ";     }     std::cout &lt;&lt; std::endl;      // Stage 2: To voltage     auto stage2 = stage1 | std::views::transform([](uint16_t v) {         return v * 3.3f / 4095.0f;     });     std::cout &lt;&lt; "As voltage: ";     for (auto v : stage2) {         std::cout &lt;&lt; std::fixed &lt;&lt; std::setprecision(3) &lt;&lt; v &lt;&lt; " ";     }     std::cout &lt;&lt; std::endl; }  void demo_calibration_curve() {     std::cout &lt;&lt; "\n=== Calibration Curve ===" &lt;&lt; std::endl;      std::vector samples = {1000, 2000, 3000, 4000};      // Two-point calibration     struct CalPoint {         uint16_t adc;         float actual;     };     CalPoint cal1 = {1000, 0.8f};     CalPoint cal2 = {4000, 3.2f};      float scale = (cal2.actual - cal1.actual) / (cal2.adc - cal1.adc);     float offset = cal1.actual - cal1.adc * scale;      auto calibrated = samples | std::views::transform([scale, offset](uint16_t adc) {         return adc * scale + offset;     });      std::cout &lt;&lt; "Calibrated voltages:" &lt;&lt; std::endl;     size_t i = 0;     for (float v : calibrated) {         std::cout &lt;&lt; "  " &lt;&lt; samples[i] &lt;&lt; " ADC -&gt; " &lt;&lt; std::fixed &lt;&lt; std::setprecision(3)                   &lt;&lt; v &lt;&lt; " V" &lt;&lt; std::endl;         i++;     } }  void demo_statistics_pipeline() {     std::cout &lt;&lt; "\n=== Statistics Pipeline ===" &lt;&lt; std::endl;      std::vector samples = {2000, 2050, 2100, 1950, 2025};      auto valid = samples         | std::views::filter([](uint16_t v) { return v &gt;= 1000 &amp;&amp; v &lt;= 3500; })         | std::views::transform([](uint16_t v) { return v * 3.3f / 4095.0f; });      float sum = 0.0f;     float min_val = 10.0f;     float max_val = 0.0f;     size_t count = 0;      for (float v : valid) {         sum += v;         min_val = std::min(min_val, v);         max_val = std::max(max_val, v);         count++;     }      if (count &gt; 0) {         float avg = sum / count;         std::cout &lt;&lt; "Statistics:" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Count: " &lt;&lt; count &lt;&lt; std::endl;         std::cout &lt;&lt; "  Min: " &lt;&lt; min_val &lt;&lt; " V" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Max: " &lt;&lt; max_val &lt;&lt; " V" &lt;&lt; std::endl;         std::cout &lt;&lt; "  Avg: " &lt;&lt; avg &lt;&lt; " V" &lt;&lt; std::endl;     } }  int main() {     demo_basic_pipeline();     demo_moving_average();     demo_stage_by_stage();     demo_calibration_curve();     demo_statistics_pipeline();      std::cout &lt;&lt; "\n=== Benefits ===" &lt;&lt; std::endl;     std::cout &lt;&lt; "- No temporary vectors between stages" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Single pass through data" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Easy to add/remove stages" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Memory efficient for embedded" &lt;&lt; std::endl;      return 0; }  ```text   <p><code>text Valid voltages:   0.0966133 V   0.185425 V   0.0540171 V   0.0717957 V</code>text</p> <p>这代码的美妙之处：</p> <ul> <li>逻辑从上到下，像讲故事一样</li> <li>没有临时变量存储中间结果</li> <li>编译器会把整个管道优化成一次遍历</li> </ul>

include  <p>class ADCProcessor { public:     // 添加ADC原始读数     void add_sample(uint16_t raw) {         samples_.push_back(raw);         keep_recent(100);  // 只保留最近100个样本     }</p> <pre><code>// 处理并返回结果
std::vector&lt;float&gt; process() {
    // 构建完整处理管道
    auto pipeline = samples_
        | std::views::filter([](uint16_t v) {
            // 阶段1：过滤掉明显无效的值
            return v &gt;= 100 &amp;&amp; v &lt;= 4000;
        })
        | std::views::transform([](uint16_t v) {
            // 阶段2：转换为电压
            return v * 3.3f / 4095.0f;
        })
        | std::views::transform([](float voltage) {
            // 阶段3：应用校准曲线（二阶多项式）
            return 1.001f * voltage + 0.0002f * voltage * voltage;
        });

    // 转换为vector返回
    return std::vector&lt;float&gt;(pipeline.begin(), pipeline.end());
}

// 获取滤波后的当前值
std::optional&lt;float&gt; get_filtered_value() {
    if (samples_.empty()) return std::nullopt;

    // 计算移动平均
    auto pipeline = samples_
        | std::views::filter([](uint16_t v) {
            return v &gt;= 100 &amp;&amp; v &lt;= 4000;
        })
        | std::views::transform([](uint16_t v) {
            return v * 3.3f / 4095.0f;
        });

    float sum = 0.0f;
    size_t count = 0;
    for (float v : pipeline) {
        sum += v;
        count++;
    }

    return count &gt; 0 ? std::optional&lt;float&gt;(sum / count) : std::nullopt;
}
