</code></pre> <p>} ```text</p>  查看完整可编译示例  ```cpp // Protocol Parsing with Ranges Pipelines // Demonstrates parsing binary protocols using ranges  #include  #include  #include  #include  #include   // Simulated SPI data reception (16-bit big-endian words) std::vector receive_spi_data() {     return {0x01, 0x00,  // 0x0100             0x00, 0x64,  // 0x0064             0x00, 0x02,  // 0x0002             0xFF, 0xFF};  // 0xFFFF (padding) }  void demo_spi_parsing() {     std::cout &lt;&lt; "=== SPI Protocol Parsing ===" &lt;&lt; std::endl;      auto data = receive_spi_data();      // Chunk into pairs     auto chunks = data | std::views::chunk(2);      std::cout &lt;&lt; "Parsed words:" &lt;&lt; std::endl;     for (auto chunk : chunks) {         if (chunk.size() == 2) {             uint16_t high = chunk[0];             uint16_t low = chunk[1];             uint16_t word = (high &lt;&lt; 8) | low;             std::cout &lt;&lt; "  0x" &lt;&lt; std::hex &lt;&lt; std::setw(4) &lt;&lt; std::setfill('0') &lt;&lt; word &lt;&lt; std::dec &lt;&lt; std::endl;         }     } }  void demo_spi_filter_padding() {     std::cout &lt;&lt; "\n=== SPI with Padding Filter ===" &lt;&lt; std::endl;      auto data = receive_spi_data();      // Chunk, convert to 16-bit, filter out padding     auto valid_words = data         | std::views::chunk(2)         | std::views::transform([](auto chunk) {             uint16_t high = chunk[0];             uint16_t low = chunk[1];             return (high &lt;&lt; 8) | low;         })         | std::views::filter([](uint16_t w) { return w != 0xFFFF; });      std::cout &lt;&lt; "Valid words (no padding):" &lt;&lt; std::endl;     for (uint16_t w : valid_words) {         std::cout &lt;&lt; "  0x" &lt;&lt; std::hex &lt;&lt; w &lt;&lt; std::dec &lt;&lt; " (" &lt;&lt; w &lt;&lt; ")" &lt;&lt; std::endl;     } }  void demo_packet_structure() {     std::cout &lt;&lt; "\n=== Structured Packet Parsing ===" &lt;&lt; std::endl;      // Packet: [CMD(1)] [LEN(1)] [DATA(N)] [CRC(2)]     std::vector packet = {         0x01,        // Command         0x04,        // Length         0x10, 0x20, 0x30, 0x40,  // Data         0xAA, 0xBB   // CRC     };      auto cmd = packet[0];     auto len = packet[1];      auto payload = std::views::drop(packet, 2);     auto data = std::views::take(payload, len);     auto crc = std::views::drop(payload, len);      std::cout &lt;&lt; "Command: 0x" &lt;&lt; std::hex &lt;&lt; static_cast(cmd) &lt;&lt; std::dec &lt;&lt; std::endl;     std::cout &lt;&lt; "Length: " &lt;&lt; static_cast(len) &lt;&lt; std::endl;     std::cout &lt;&lt; "Data: ";     for (uint8_t b : data) {         std::cout &lt;&lt; std::hex &lt;&lt; "0x" &lt;&lt; static_cast(b) &lt;&lt; " " &lt;&lt; std::dec;     }     std::cout &lt;&lt; std::endl;     std::cout &lt;&lt; "CRC: ";     for (uint8_t b : crc) {         std::cout &lt;&lt; std::hex &lt;&lt; "0x" &lt;&lt; static_cast(b) &lt;&lt; " " &lt;&lt; std::dec;     }     std::cout &lt;&lt; std::endl; }  void demo_nmea_sentence() {     std::cout &lt;&lt; "\n=== NMEA Sentence Parsing ===" &lt;&lt; std::endl;      std::string nmea = "$GPGGA,123519,4807.038,N,01131.000,E,1,08,0.9,545.4,M,46.9,M,,*47";      // Remove checksum for demo     auto clean = std::views::take(nmea, nmea.find('*'));      // Split by comma     auto parts = std::views::split(clean, ',');      const char* field_names[] = {"Type", "Time", "Lat", "NS", "Lon", "EW", "Quality", "Sats"};     int idx = 0;      for (auto part : parts) {         std::string_view sv(part.begin(), part.end());         if (idx &lt; 8) {             std::cout &lt;&lt; "  " &lt;&lt; field_names[idx] &lt;&lt; ": " &lt;&lt; sv &lt;&lt; std::endl;         }         idx++;         if (idx &gt;= 8) break;     } }  void demo_variable_length_packets() {     std::cout &lt;&lt; "\n=== Variable Length Packets ===" &lt;&lt; std::endl;      // Stream with multiple packets     std::vector stream = {         // Packet 1         0xAA, 0x02, 0x10, 0x20,         // Packet 2         0xAA, 0x03, 0x11, 0x22, 0x33,         // Packet 3         0xAA, 0x01, 0x40     };      size_t pos = 0;     while (pos &lt; stream.size()) {         // Check for sync byte         if (stream[pos] == 0xAA) {             if (pos + 1 &lt; stream.size()) {                 uint8_t len = stream[pos + 1];                  if (pos + 2 + len &lt;= stream.size()) {                     std::cout &lt;&lt; "Packet at pos " &lt;&lt; pos &lt;&lt; ", len " &lt;&lt; static_cast(len) &lt;&lt; ": ";                      auto packet_data = std::views::drop(stream, pos + 2)                                      | std::views::take(len);                      for (uint8_t b : packet_data) {                         std::cout &lt;&lt; std::hex &lt;&lt; "0x" &lt;&lt; static_cast(b) &lt;&lt; " " &lt;&lt; std::dec;                     }                     std::cout &lt;&lt; std::endl;                      pos += 2 + len;                     continue;                 }             }         }         pos++;     } }  void demo_hex_dump_pipeline() {     std::cout &lt;&lt; "\n=== Hex Dump Pipeline ===" &lt;&lt; std::endl;      std::vector data = {0x01, 0x02, 0x03, 0x04, 0x05};      // Format as hex dump     auto hex_format = data | std::views::transform([](uint8_t b) {         char buf[8];         snprintf(buf, sizeof(buf), "0x%02X", b);         return std::string(buf);     });      std::cout &lt;&lt; "Hex dump: ";     for (const auto&amp; s : hex_format) {         std::cout &lt;&lt; s &lt;&lt; " ";     }     std::cout &lt;&lt; std::endl; }  int main() {     demo_spi_parsing();     demo_spi_filter_padding();     demo_packet_structure();     demo_nmea_sentence();     demo_variable_length_packets();     demo_hex_dump_pipeline();      std::cout &lt;&lt; "\n=== Key Points ===" &lt;&lt; std::endl;     std::cout &lt;&lt; "- chunk(n) splits range into n-element subranges" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Pipelines allow complex parsing in readable form" &lt;&lt; std::endl;     std::cout &lt;&lt; "- No temporary storage for intermediate results" &lt;&lt; std::endl;     std::cout &lt;&lt; "- Perfect for embedded protocol parsing" &lt;&lt; std::endl;      return 0; }  ```text   <p><code>text Word: 0x100 Word: 0x64 Word: 0x2</code>text</p> <p><code>std::views::chunk</code>是个很实用的视图适配器，它把N个元素分成一组，非常适合处理协议数据。</p>

