include  <p>// 简单的环形缓冲区 template class RingBuffer { public:     void push(T value) {         data_[head_] = value;         head_ = (head_ + 1) % N;         if (size_ &lt; N) size_++;     } <pre><code>// 让它成为Range：提供begin/end
